        while (!tlv.IsEndContainerNext())
        {
            switch (tlv.PeekTag())
            {
                case 0:
                    value.CredentialType = (CredentialTypeEnum)tlv.GetUnsignedIntAny(0);
                    break;
                case 1:
                    value.CredentialIndex = (ushort)tlv.GetUnsignedIntAny(1);
                    break;
                default:
                    tlv.SkipElement();
                    break;
            }
        }

        tlv.CloseContainer();
        return value;
    }

