    public Task<InvokeResponse> LockDoorAsync(
        byte[]? pINCode = default,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0000, tlv => { if (pINCode != null) tlv.AddOctetString(0, pINCode); }, ct);

